import React from 'react';
import {
    Dialog,
    DialogTitle,
    DialogContent,
    Box,
    Typography,
    IconButton
} from '@mui/material';

import CloseIcon from '@mui/icons-material/Close';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';

// 🔥 IMPORT FROM MODULES
import AdminRouteView from 'modules/admin/components/AdminRouteView';
import EmployeeRouteView from 'modules/employee/components/EmployeeRouteView';

const EmployeeRouteModal = ({ open, onClose, employee, role }) => {

    return (
        <Dialog open={open} onClose={onClose} fullScreen>

            {/* HEADER */}
            <DialogTitle sx={{ display: 'flex', justifyContent: 'space-between' }}>
                <Box display="flex" alignItems="center" gap={1}>
                    <IconButton onClick={onClose}>
                        <ArrowBackIcon />
                    </IconButton>

                    <Typography fontWeight="bold">
                        {employee?.name} - Route Tracking
                    </Typography>
                </Box>

                <IconButton onClick={onClose}>
                    <CloseIcon />
                </IconButton>
            </DialogTitle>

            <DialogContent>

                {/* 🔥 ROLE SWITCH */}
                {role === 'ADMIN' ? (
                    <AdminRouteView employee={employee} />
                ) : (
                    <EmployeeRouteView employee={employee} />
                )}

            </DialogContent>

        </Dialog>
    );
};

export default EmployeeRouteModal;